using System;using System.Collections.Generic;using System.IO;using System.Text;namespace LemonFramework.UProfiler.Core{    [Serializable]    public struct RenderInfo : IBinarySerializable    {        public int frameIndex;        public long setPassCall;        public long drawCall;        //Vertex count.        public long vertices;        //Triangle count        public long triangles;        public void DeSerialize(BinaryReader reader)        {            frameIndex = reader.ReadInt32();            setPassCall = reader.ReadInt64();            drawCall = reader.ReadInt64();            vertices = reader.ReadInt64();            triangles = reader.ReadInt64();        }        public void Serialize(BinaryWriter writer)        {            writer.Write(frameIndex);            writer.Write(setPassCall);            writer.Write(drawCall);            writer.Write(vertices);            writer.Write(triangles);        }        public override string ToString()        {            return                $"Frame:{frameIndex} SetPassCall:{setPassCall} DrawCall:{drawCall} Vertices:{vertices} Triangles:{triangles}";        }    }    [Serializable]    public class RenderInfos : IBinarySerializable    {        public List<RenderInfo> renderInfoList = new List<RenderInfo>();        private StringBuilder _stringBuilder = new StringBuilder();        public void DeSerialize(BinaryReader reader)        {            int count = reader.ReadInt32();            for (int i = 0; i < count; i++)            {                var tempData = new RenderInfo();                tempData.DeSerialize(reader);                renderInfoList.Add(tempData);            }        }        public void Serialize(BinaryWriter writer)        {            writer.Write(renderInfoList.Count);            for (int i = 0; i < renderInfoList.Count; i++)            {                renderInfoList[i].Serialize(writer);            }        }        public override string ToString()        {            _stringBuilder.Clear();            for (int i = 0; i < renderInfoList.Count; i++)            {                _stringBuilder.Append(renderInfoList[i].ToString());                _stringBuilder.Append('\n');            }            return _stringBuilder.ToString();        }    }}